#include <bits/stdc++.h>
using namespace std;

const int N=5010,mod=1e9+7;

int n,b[N],f[N][N],sz[N],g[N];
int fac[N],inv[N],p[N];
vector<int> e[N];

void init(){
    fac[0]=1;
    for(int i=1;i<N;i++)
        fac[i]=1ll*fac[i-1]*i%mod;
    p[0]=p[1]=1;
    for(int i=2;i<N;i++)
        p[i]=mod-1ll*(mod/i)*p[mod%i]%mod;
    inv[0]=1;
    for(int i=1;i<N;i++)
        inv[i]=1ll*inv[i-1]*p[i]%mod;
}

int C(int n,int m){
    if(n<m || m<0)
        return 0;
    return 1ll*fac[n]*inv[n-m]%mod*inv[m]%mod;
}

long long qpow(int a,int b){
    long long ans=1,base=a;
    while(b){
        if(b&1)
            ans=ans*base%mod;
        base=base*base%mod,b>>=1;
    }
    return ans;
}

void dfs1(int u){
    sz[u]=1;
    g[u]=1;
    for(int v:e[u]){
        dfs1(v);
        sz[u]+=sz[v];
        g[u]=1ll*g[u]*g[v]%mod;
    }
    g[u]=1ll*g[u]*p[sz[u]]%mod;
}

void dfs2(int u){
    for(int v:e[u]){
        int num=g[u]*qpow(1ll*g[v]*C(sz[u]-1,sz[v])%mod,mod-2)%mod;
        for(int i=0;i<n;i++)
            f[v][i+1]=(f[v][i]+1ll*f[u][i]*num%mod*C(n-i-sz[v],sz[u]-sz[v]-1))%mod;
        dfs2(v);
    }
}

int main(){
    scanf("%d",&n);
    for(int i=2;i<=n;i++){
        int u;
        scanf("%d",&u);
        e[u].push_back(i);
    }
    for(int i=1;i<=n;i++)
        scanf("%d",&b[i]);
    init();
    f[1][1]=1;
    dfs1(1);
    for(int i=1;i<=n;i++)
        g[i]=1ll*g[i]*fac[sz[i]]%mod;
    dfs2(1);
    for(int i=1;i<=n;i++){
        int ans=0;
        for(int j=1;j<=n;j++)
            ans=(ans+1ll*b[j]*f[i][j]%mod*C(n-j,sz[i]-1)%mod*g[i])%mod;
        printf("%d ",ans);
    }
    return 0;
}
